const customers = [
  { name: 'A', orders: [{ amount: 10 }, { amount: 30 }, { amount: 20 }] },
  { name: 'B', orders: [{ amount: 5 }, { amount: 8 }] },
  { name: 'C', orders: [{ amount: 100 }, { amount: 50 }, { amount: 75 }, { amount: 20 }] },
];

const result = customers
  .filter((c) => c.orders.length >= 3)
  .map((c) => ({
    name: c.name,
    biggest: c.orders.reduce((max, o) => Math.max(max, o.amount), 0),
  }));

console.log(result);

